using System.ComponentModel;
using System.Net;
using System.Text.Json;

namespace ResearchAgent;

/// <summary>
/// Tools the research agent can invoke during a research session.
/// </summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    // ── Web Search ──────────────────────────────────────────────────────

    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query)
    {
        // Use the free DuckDuckGo Instant Answer API (no key required).
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1";

        try
        {
            var json = await _httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main summary)
            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                results.Add($"[{source}] {abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add(text);
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try rephrasing the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    // ── Note-Taking ─────────────────────────────────────────────────────

    [Description("Save a research note. Use this to record important findings.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n",
            _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

