using System.ClientModel;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent;

// ── Configuration ───────────────────────────────────────────────────────
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run this agent.");
    return 1;
}

// ── Build the chat client with tool support ─────────────────────────────
var tools = new ResearchTools();

IChatClient client = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools = [
        AIFunctionFactory.Create(tools.SearchWebAsync),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]
};

// ── Get the research topic ──────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching \"{topic}\"…\n");

// ── Run the agent loop ──────────────────────────────────────────────────
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Given a topic, you:
        1. Search the web for relevant information (make multiple searches if needed).
        2. Save important findings as notes.
        3. After gathering enough information, review your notes and produce a
           well-structured summary of the topic.
        Always save at least a few notes before writing the final summary.
        """),
    new(ChatRole.User, $"Research this topic and provide a summary: {topic}")
};

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══ Research Summary ═══\n");
Console.WriteLine(response.Text);

return 0;

